# setup_i18n.ps1 - Sistema de traducciones ES/IT
Write-Host "Instalando sistema de idiomas ES/IT..." -ForegroundColor Cyan

$dir = Split-Path "src\store\lang.store.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\store\lang.store.ts", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/store/lang.store.ts" -ForegroundColor Yellow

